<a id="Selectable Rows Table">
  <h2>Selectable Rows Table</h2>
</a>

Place a <code>Checkbox</code> in the first cell of each row and in the header row for select-all behaviour.

<div className="showcase">
  <div className="items">
    <ThemeWrapper>
      <SelectableTableDemo />
    </ThemeWrapper>
  </div>
  <CodeBlock name="selectable-table" collapsible code={`import { useState } from "react";
import {
  Table, TableHead, TableBody, TableRow, TableCell,
  Checkbox, TableContainer, Paper,
} from "@sistent/sistent";

const data = [
  { name: "Alice", env: "production" },
  { name: "Bob", env: "staging" },
  { name: "Charlie", env: "development" },
];

export default function SelectableTable() {
  const [selected, setSelected] = useState([]);

  const isSelected = (index) => selected.indexOf(index) !== -1;

  const handleSelectAll = () => {
    if (selected.length === data.length) {
      setSelected([]);
    } else {
      setSelected(data.map((_, i) => i));
    }
  };

  const handleSelect = (index) => {
    const pos = selected.indexOf(index);
    if (pos === -1) {
      setSelected([...selected, index]);
    } else {
      setSelected(selected.filter((i) => i !== index));
    }
  };

  return (
    <TableContainer component={Paper} elevation={1}>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell padding="checkbox">
              <Checkbox
                indeterminate={
                  selected.length > 0 &&
                  selected.length < data.length
                }
                checked={
                  data.length > 0 &&
                  selected.length === data.length
                }
                onChange={handleSelectAll}
              />
            </TableCell>
            <TableCell>Name</TableCell>
            <TableCell>Environment</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {data.map((row, index) => (
            <TableRow
              key={row.name}
              hover
              selected={isSelected(index)}
              onClick={() => handleSelect(index)}
              sx={{ cursor: "pointer" }}
            >
              <TableCell padding="checkbox">
                <Checkbox checked={isSelected(index)} />
              </TableCell>
              <TableCell>{row.name}</TableCell>
              <TableCell>{row.env}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
}`} />
</div>

